{
  "verses": [
    {
      "n": 21,
      "column": "left",
      "text": "Un tas mehdiia Israēln:\nBet Ionataus/ Simeja/ Dah-\nwida Brahta Dehls/ kawe to.\n"
    },
    {
      "n": 22,
      "column": "left",
      "text": "Ochee tſchetri bija Ra-\nwum Gattā dfimmuschi/ un krit-\nte zaure Dahwida Rohku/ un\njaur wiꞥſch Kalpu Rohku.\n"
    },
    {
      "n": 1,
      "column": "left",
      "text": "N Dahwids runnaja\npreekſch ta KUNG A\nſchihs Dseefinas Wahr-\ndus/ tai Deena/ tad tas KUNgs\nwinnu btj atpestijs no wiſſeem\nwinna Eenaidneeekein / un no\nSaula Rohkas/ un wiꞥſch tuz-\nzija:\n"
    },
    {
      "n": 2,
      "column": "left",
      "text": "Tas KUNGS irr mans\nAknuina-Kalns/un manna Pils/\nun mans Isglahbeis.\n"
    },
    {
      "n": 3,
      "column": "left",
      "text": "Deews irr mans Patwe-\nrums/ us ko es palaischohs/man-\nnas preeſſchturrannas Bruzznas/\nun mannas Pestifchanas Rags/\nmanna angsta Gelbeschana / un\nmanna Skahschana/ mans Pe-\nſtitajs / kas man no Warras-\nDarba atvesti.\n"
    },
    {
      "n": 4,
      "column": "left",
      "text": "Es peefankſchu to KUNG-\nGii/ kas teizams/ tad tapſchn es\n"
    },
    {
      "n": 5,
      "column": "right",
      "text": "Jo Nahwes Wilni apg\nbe manni/ un Beliala Upp-\nbeedeja manni.\n"
    },
    {
      "n": 6,
      "column": "right",
      "text": "Tahs Elles Saiteg ap\nme manni/ un tahs Na-\nSaiteg pahrwarreja manni\n"
    },
    {
      "n": 7,
      "column": "right",
      "text": "Kad man Behdasirr\npeefanzu es to KUNGII/e-\nfanzu mannu Deewu/ tad\nfa wiꞥſch mannu Balfino\nDeewa Namma / un ni-\nBrehfschana nahf preekſch\nna Ausin.\n"
    },
    {
      "n": 8,
      "column": "right",
      "text": "Ta Semme tapp\ne\nnata un drebbeja/ un tahs\nbes Stiprumi kustejahs/un\nfeja winnam apſkaitoht.\n"
    },
    {
      "n": 9,
      "column": "right",
      "text": "Duhmi uskahpe no n\nRabſim/ un rihjams Ugau\nwinna Muttes/ Sibvini\ndse no winna.\n"
    },
    {
      "n": 10,
      "column": "right",
      "text": "Wiꞥſch lohzija to D\nfi/ un nolaſdahs / un Kre-\nbija appakſch winna Kahja\n"
    },
    {
      "n": 11,
      "column": "right",
      "text": "Un wiꞥſch brauze u\nrubu / un skrehje / un u-\nskrehe ahtri us ta Webja S-\nneem.\n"
    },
    {
      "n": 12,
      "column": "right",
      "text": "Wiꞥſch likfe Tu-\napkahrt tew par Telti / ir\nUydeni/ un beesas Padebb\n"
    },
    {
      "n": 13,
      "column": "right",
      "text": "No ta Spohschuma\nra Preeſſcha eedede Sibbi-\nUgguni.\n"
    },
    {
      "n": 14,
      "column": "right",
      "text": "Tas KUNgs likfe\nfonus rihbeht no Debbes/u-\nwiffuangstajs islaide faiw-\nkoni:\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
